 {"id":"bd-mblr.2","title":"No-Mock Real-Backend Test Expansion","description":"Expand test suites so critical invariants are validated against real components (real pager/wal/mvcc/btree/vfs paths), not only mocks/fakes or in-memory substitutes.","design":"Retain mock tests for contracts, but require real-stack behavior tests for invariants.","acceptance_criteria":"Critical paths validated by at least one real-backend non-mock test each; fault-injection recovery paths verified; file-backed lifecycle tests added.","notes":"Deferred intentionally for queue hygiene: this bead is a container/coordination umbrella, not a direct implementation lane. Work proceeds through its child tasks; reopen/close this bead during milestone rollup and completion review.","status":"deferred","priority":1,"issue_type":"epic","created_at":"2026-02-12T23:23:16.819632916Z","created_by":"ubuntu","updated_at":"2026-02-13T00:51:03.694818719Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2","depends_on_id":"bd-mblr","type":"parent-child","created_at":"2026-02-12T23:23:16.819632916Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2","depends_on_id":"bd-mblr.1","type":"blocks","created_at":"2026-02-12T23:25:05.852519634Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":1340,"issue_id":"bd-mblr.2","author":"Dicklesworthstone","text":"Detailed scope: prioritize behavior-invariant tests over interface-contract tests. Existing mock exports (pager and btree traits) remain useful for unit isolation, but cannot be sole evidence for correctness of integrated persistence, concurrency, and recovery flows.","created_at":"2026-02-12T23:26:03Z"}]}
 {"id":"bd-mblr.2.1","title":"Pager/WAL/MVCC/B-Tree Real-Backend Composition Tests","description":"Add composition tests that run through real pager+wal+mvcc+btree interactions for commit, rollback, checkpoint, crash-replay, and conflict paths. Keep mock tests for trait contracts, but add real-stack tests for behavior-critical invariants.","design":"Build reusable integration harness primitives (DB setup, workload runner, invariant verifier) to avoid copy-paste tests with inconsistent assertions.","acceptance_criteria":"- Composition tests exercise pager, WAL, MVCC, B-tree, and VFS on real file-backed paths for commit/rollback/checkpoint/replay/conflict flows.
- Assertions check invariant IDs (durability, visibility, conflict semantics) rather than only API return codes.
- Failure output includes seed/fixture metadata and minimal repro commands.","notes":"This track is the hard proof that concurrent-writer behavior is preserved under real storage execution paths.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-12T23:23:53.629218207Z","created_by":"ubuntu","updated_at":"2026-02-13T00:04:43.355519038Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.1","depends_on_id":"bd-mblr.1.3","type":"blocks","created_at":"2026-02-12T23:25:08.953195576Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.1","depends_on_id":"bd-mblr.2","type":"parent-child","created_at":"2026-02-12T23:23:53.629218207Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.2.1.1","title":"Real-backend composition harness","description":"Create composition tests that exercise pager/WAL/MVCC/B-tree over real file-backed VFS paths, not trait mocks. Output: harness + deterministic assertions for integrated behavior.","design":"Use small composable fixtures for files, page sizes, and transaction windows so higher-level tests can vary one factor at a time.","acceptance_criteria":"- Harness can instantiate real backend stack without trait mocks for deterministic scenarios.
- Harness supports controlled setup/teardown, seeded workloads, and state inspection checkpoints.
- At least one end-to-end smoke scenario per major storage subsystem passes through harness.","notes":"Treat this as foundational plumbing for bd-mblr.2.1.2, 2.2.*, and 2.3.*.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-12T23:37:52.283916314Z","created_by":"ubuntu","updated_at":"2026-02-13T00:04:43.421158941Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.1.1","depends_on_id":"bd-mblr.1.3.2","type":"blocks","created_at":"2026-02-12T23:38:31.847723219Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.1.1","depends_on_id":"bd-mblr.2.1","type":"parent-child","created_at":"2026-02-12T23:37:52.283916314Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
